from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent, single‑sentence description from a list of triples about a monument."""
    if not triples:
        return ""

    # The first triple’s subject is taken as the main subject.
    main_subject = triples[0].subject

    # Gather predicates that belong to the main subject.
    main_info: dict[str, str] = {}
    # Keep triples about other entities for relative clauses.
    extra_triples: list[Triple] = []

    for t in triples:
        if t.subject == main_subject:
            main_info[t.predicate] = t.object
        else:
            extra_triples.append(t)

    clauses: list[str] = []

    # 1️⃣  Basic identification
    if "category" in main_info:
        clauses.append(f"{main_subject} is a {main_info['category']}")
    else:
        clauses.append(f"{main_subject} is a monument")

    # 2️⃣  Location hierarchy (most specific → most general)
    loc_order = ("municipality", "location", "district", "state", "country")
    loc_parts = [main_info[k] for k in loc_order if k in main_info]
    if loc_parts:
        clauses.append(f"located in {', '.join(loc_parts)}")

    # 3️⃣  Dates
    date_phrases = {
        "established": "established on",
        "foundingDate": "founded on",
        "inaugurationDate": "inaugurated on",
    }
    for pred, phr in date_phrases.items():
        if pred in main_info:
            clauses.append(f"{phr} {main_info[pred]}")

    # 4️⃣  Dedicated to
    if "dedicatedTo" in main_info:
        clauses.append(f"dedicated to {main_info['dedicatedTo']}")

    # 5️⃣  Designer
    if "designer" in main_info:
        clauses.append(f"designed by {main_info['designer']}")

    # 6️⃣  Material
    if "material" in main_info:
        clauses.append(f"made of {main_info['material']}")

    # 7️⃣  Ownership
    if "owner" in main_info:
        clauses.append(f"owned by {main_info['owner']}")
    elif "owningOrganisation" in main_info:
        clauses.append(f"owned by {main_info['owningOrganisation']}")

    # 8️⃣  Extra information as relative clauses
    rel_map = {
        "nearestCity": "which is nearest to",
        "hasToItsNorth": "which has to its north",
        "hasToItsSouthwest": "which has to its southwest",
        "hasToItsWest": "which has to its west",
        "hasToItsSoutheast": "which has to its southeast",
    }
    for t in extra_triples:
        if t.predicate in rel_map:
            phrase = rel_map[t.predicate]
            # incorporate the subject of this triple (e.g., a district) into the main clause
            if t.subject in loc_parts:
                # already mentioned as location – turn into a relative clause
                clauses.append(f"{phrase} {t.object}")
            else:
                clauses.append(f"{t.subject} {phrase} {t.object}")

    # Helper to join clauses with commas and a final “and”
    def join_clauses(clist: list[str]) -> str:
        if not clist:
            return ""
        if len(clist) == 1:
            return clist[0]
        return ", ".join(clist[:-1]) + ", and " + clist[-1]

    sentence = join_clauses(clauses) + "."
    return sentence

# EVOLVE-BLOCK-END

